import { Sudoku } from './sudoku';
import { cursor } from './stores/cursor';
import { difficulty } from './stores/difficulty';
import { gamePaused } from './stores/game';
import { timer } from './stores/timer';
import { hints } from './stores/hints';

export class Game {
    constructor() {
        this.sudoku = null;
        this.history = [];
        this.isPaused = false;
    }

    /**
     * 对应原 startNew 函数逻辑
     */
    startNew(diff) {
        difficulty.set(diff);
        this.sudoku = Sudoku.generate(diff);
        this.history = [];
        
        // 重置外部状态
        cursor.reset();
        timer.reset();
        hints.reset();
        this.resume();
        location.hash = '';
    }

    /**
     * 核心：执行一步操作
     */
    makeMove(row, col, value) {
        if (this.isPaused) return;
        
        // 存入历史记录
        this.history.push(this.sudoku.clone());
        this.sudoku.guess(row, col, value);
    }

    /**
     * 撤销
     */
    undo() {
        if (this.history.length > 0) {
            this.sudoku = this.history.pop();
        }
    }

    pause() {
        timer.stop();
        gamePaused.set(true);
        this.isPaused = true;
    }

    resume() {
        timer.start();
        gamePaused.set(false);
        this.isPaused = false;
    }
}

// 导出单例方便直接使用
export default new Game();
